  1272→    // ====== Signature Canvas ======
  1273→    function initSignatureCanvas() {
  1274→      const canvas = document.getElementById('signatureCanvas');
  1275→      if (!canvas) return;
  1276→
  1277→      signatureCanvas = canvas;
  1278→      signatureCtx = canvas.getContext('2d');
  1279→
  1280→      // Set canvas size
  1281→      const rect = canvas.parentElement.getBoundingClientRect();
  1282→      canvas.width = rect.width - 48;
  1283→      canvas.height = 150;
  1284→
  1285→      signatureCtx.strokeStyle = '#1a1a2e';
  1286→      signatureCtx.lineWidth = 2;
  1287→      signatureCtx.lineCap = 'round';
  1288→      signatureCtx.lineJoin = 'round';
  1289→
  1290→      canvas.addEventListener('mousedown', startDrawing);
  1291→      canvas.addEventListener('mousemove', draw);
  1292→      canvas.addEventListener('mouseup', stopDrawing);
  1293→      canvas.addEventListener('mouseleave', stopDrawing);
  1294→
  1295→      // Touch support
  1296→      canvas.addEventListener('touchstart', (e) => {
  1297→        e.preventDefault();
  1298→        const touch = e.touches[0];
  1299→        const rect = canvas.getBoundingClientRect();
  1300→        startDrawing({ offsetX: touch.clientX - rect.left, offsetY: touch.clientY - rect.top });
  1301→      });
  1302→      canvas.addEventListener('touchmove', (e) => {
  1303→        e.preventDefault();
  1304→        const touch = e.touches[0];
  1305→        const rect = canvas.getBoundingClientRect();
  1306→        draw({ offsetX: touch.clientX - rect.left, offsetY: touch.clientY - rect.top });
  1307→      });
  1308→      canvas.addEventListener('touchend', stopDrawing);
  1309→    }
  1310→
  1311→    function startDrawing(e) {
  1312→      isDrawing = true;
  1313→      signatureCtx.beginPath();
  1314→      signatureCtx.moveTo(e.offsetX, e.offsetY);
  1315→    }
  1316→
  1317→    function draw(e) {
  1318→      if (!isDrawing) return;
  1319→      signatureCtx.lineTo(e.offsetX, e.offsetY);
  1320→      signatureCtx.stroke();
  1321→      hasSigned = true;
  1322→      const btn = document.getElementById('signAllBtn');
  1323→      if (btn) btn.disabled = false;
  1324→    }
  1325→
  1326→    function stopDrawing() {
  1327→      isDrawing = false;
  1328→    }
  1329→
  1330→    function clearSignature() {
  1331→      if (!signatureCanvas || !signatureCtx) return;
  1332→      signatureCtx.clearRect(0, 0, signatureCanvas.width, signatureCanvas.height);
  1333→      hasSigned = false;
  1334→      const btn = document.getElementById('signAllBtn');
  1335→      if (btn) btn.disabled = true;
  1336→    }
  1337→
  1338→    function typeSignature() {
  1339→      const name = prompt('Type your full legal name as your signature:');
  1340→      if (!name || !name.trim()) return;
  1341→
  1342→      if (!signatureCanvas || !signatureCtx) return;
  1343→      signatureCtx.clearRect(0, 0, signatureCanvas.width, signatureCanvas.height);
  1344→      signatureCtx.font = 'italic 32px "Times New Roman", serif';
  1345→      signatureCtx.fillStyle = '#1a1a2e';
  1346→      signatureCtx.textAlign = 'center';
  1347→      signatureCtx.fillText(name.trim(), signatureCanvas.width / 2, 90);
  1348→      hasSigned = true;
  1349→      const btn = document.getElementById('signAllBtn');
  1350→      if (btn) btn.disabled = false;
  1351→    }
