    13→// Auth check - uses checkAuth() from main.js which handles token properly
    14→async function initAuth() {
    15→  try {
    16→    // Use checkAuth from main.js which includes proper Authorization header
    17→    const user = await checkAuth();
    18→    if (!user) {
    19→      window.location.href = '/login.html';
    20→      return;
