    26→    document.getElementById('user-name').textContent = userName;
    27→    document.getElementById('user-avatar').textContent = userName.charAt(0).toUpperCase();
    28→
    29→    // Check plan status
    30→    if (user.is_paid) {
    31→      document.getElementById('user-plan').textContent = 'Pro Plan';
    32→    }
    33→
    34→    // Load stats and documents
    35→    await Promise.all([
    36→      loadStats(),
    37→      loadDocuments()
