    50→
    51→    const stats = data.stats;
    52→
    53→    document.getElementById('total-docs').textContent = stats.total_documents || 0;
    54→    document.getElementById('verified-docs').textContent = stats.verified_documents || 0;
    55→    document.getElementById('verified-credentials').textContent = stats.verified_credentials || 0;
    56→
    57→    const scoreBoost = stats.total_score_impact || 0;
    58→    document.getElementById('score-boost').textContent = scoreBoost > 0 ? `+${scoreBoost}` : scoreBoost;
    59→  } catch (error) {
    60→    console.error('Error loading stats:', error);
    61→  }
    62→}
    63→
    64→// Load all documents - uses apiCall from main.js for proper auth
    65→async function loadDocuments() {
    66→  try {
    67→    const data = await apiCall('/documents');
    68→    if (!data) return;
    69→
    70→    documents = data.documents || [];
    71→
    72→    renderDocuments();
    73→  } catch (error) {
    74→    console.error('Error loading documents:', error);
    75→    showEmptyState('Failed to load documents. Please refresh.');
