    94→    return `
    95→      <div class="document-item" onclick="viewDocument(${doc.id})">
    96→        <div class="doc-icon">${icon}</div>
    97→        <div class="doc-info">
    98→          <div class="doc-name">${doc.original_filename}</div>
    99→          <div class="doc-meta">
   100→            ${formatDocType(doc.document_type)} • Uploaded ${formatDate(doc.uploaded_at)}
   101→          </div>
