   653→// Get onboarding summary for recruiter dashboard (candidates with pending docs)
   654→router.get('/recruiter/summary', authMiddleware, async (req, res) => {
   655→  try {
   656→    // Verify user is a recruiter
   657→    if (!req.user.company_id) {
   658→      return res.status(403).json({ error: 'Only recruiters can view onboarding documents' });
   659→    }
   660→
   661→    const result = await pool.query(
   662→      `SELECT
   663→        u.id as candidate_id,
   664→        u.name as candidate_name,
   665→        u.email as candidate_email,
   666→        COUNT(od.id) as total_documents,
   667→        SUM(CASE WHEN od.status = 'completed' OR od.signed_at IS NOT NULL THEN 1 ELSE 0 END) as signed_documents,
   668→        MAX(od.created_at) as last_activity,
   669→        oc.status as checklist_status,
   670→        oc.due_date,
   671→        j.title as job_title,
   672→        cod.wizard_status,
   673→        cod.current_step as wizard_step
   674→      FROM users u
   675→      JOIN offers o ON u.id = o.candidate_id
   676→      LEFT JOIN onboarding_checklists oc ON u.id = oc.candidate_id
   677→      LEFT JOIN onboarding_documents od ON u.id = od.candidate_id
   678→      LEFT JOIN jobs j ON o.job_id = j.id
   679→      LEFT JOIN candidate_onboarding_data cod ON u.id = cod.candidate_id AND cod.checklist_id = oc.id
   680→      WHERE o.company_id = $1 AND o.status IN ('accepted', 'completed')
   681→      GROUP BY u.id, u.name, u.email, oc.status, oc.due_date, j.title, cod.wizard_status, cod.current_step
   682→      ORDER BY u.created_at DESC`,
   683→      [req.user.company_id]
   684→    );
   685→
   686→    // Derive real status from actual document progress (not checklist which may be fake-completed)
   687→    const candidates = result.rows.map(r => {
   688→      const totalDocs = parseInt(r.total_documents) || 0;
   689→      const signedDocs = parseInt(r.signed_documents) || 0;
   690→      let onboarding_status;
   691→
   692→      if (r.wizard_status === 'completed' && totalDocs > 0 && signedDocs === totalDocs) {
   693→        onboarding_status = 'completed';
   694→      } else if (totalDocs > 0 || r.wizard_step > 1) {
   695→        onboarding_status = 'in_progress';
   696→      } else {
   697→        onboarding_status = 'pending';
   698→      }
   699→
   700→      return {
   701→        candidate_id: r.candidate_id,
   702→        candidate_name: r.candidate_name,
   703→        candidate_email: r.candidate_email,
   704→        total_documents: r.total_documents,
   705→        signed_documents: r.signed_documents,
   706→        last_activity: r.last_activity,
   707→        onboarding_status,
   708→        due_date: r.due_date,
   709→        job_title: r.job_title,
   710→        wizard_step: r.wizard_step
   711→      };
   712→    });
   713→
   714→    res.json(candidates);
   715→  } catch (err) {
   716→    console.error('Error fetching onboarding summary:', err);
   717→    res.status(500).json({ error: 'Failed to fetch summary' });
   718→  }
   719→});
